package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.Constructor;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static Class<?> recordClass;
  private static Class<?> nonRecordClass;

  @BeforeAll
  static void setup() {
    // Create a record class dynamically if possible (Java 16+), otherwise use a known record class.
    // For testing, use a known record or simulate with a mock.
    recordClass = RecordSample.class;
    nonRecordClass = NonRecordSample.class;
  }

  @Test
  void testIsRecord_withRecordClass_returnsTrue() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      // The static field RECORD_HELPER is private, so we use reflection to mock its behavior.
      var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
      recordHelperField.setAccessible(true);
      RecordHelper mockRecordHelper = mock(RecordHelper.class);
      when(mockRecordHelper.isRecord(recordClass)).thenReturn(true);
      recordHelperField.set(null, mockRecordHelper);

      boolean result = ReflectionHelper.isRecord(recordClass);
      assertTrue(result);
      verify(mockRecordHelper).isRecord(recordClass);
    } catch (Exception e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  @Test
  void testIsRecord_withNonRecordClass_returnsFalse() {
    try (MockedStatic<ReflectionHelper> mockedStatic = Mockito.mockStatic(ReflectionHelper.class, Mockito.CALLS_REAL_METHODS)) {
      var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
      recordHelperField.setAccessible(true);
      RecordHelper mockRecordHelper = mock(RecordHelper.class);
      when(mockRecordHelper.isRecord(nonRecordClass)).thenReturn(false);
      recordHelperField.set(null, mockRecordHelper);

      boolean result = ReflectionHelper.isRecord(nonRecordClass);
      assertFalse(result);
      verify(mockRecordHelper).isRecord(nonRecordClass);
    } catch (Exception e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  // Dummy record class for testing (Java 16+)
  public record RecordSample(String name, int id) {}

  // Dummy non-record class
  public static class NonRecordSample {
    private String name;
    private int id;
  }
}
